callGraph.callee:
record
            .into_rows()
            .map(|(op, row)| {
                let mut data = row.into_inner();

                for (datum, r#gen) in data
                    .iter_mut()
                    .zip_eq_fast(vars.field_generators.iter_mut())
                {
                    match rand::rng().random_range(0..4) {
                        0 | 1 => {
                            // don't change the value
                        }
                        2 => {
                            *datum = None;
                        }
                        3 => {
                            *datum = r#gen
                                .as_mut()
                                .and_then(|r#gen| r#gen.generate_datum(rand::random()))
                                .or(datum.take());
                        }
                        _ => unreachable!(),
                    }
                }

                (op, OwnedRow::new(data.into_vec()))
            }).collect

current_watermark
                        .clone()
                        .map(|watermark| {
                            Self::build_watermark_filter_expr(
                                watermark_type.clone(),
                                event_time_col_idx,
                                watermark,
                                eval_error_report.clone(),
                            )
                        }).transpose

data_types
                .iter()
                .enumerate()
                .map(|(id, data_type)| PbColumnCatalog {
                    column_desc: Some(
                        ColumnDesc::unnamed(ColumnId::new(id as i32), data_type.clone())
                            .to_protobuf(),
                    ),
                    is_hidden: false,
                }).collect

match &message {
            Message::Chunk(chunk) => risingwave_common::util::schema_check::schema_check(
                info.schema.fields().iter().map(|f| &f.data_type),
                chunk.columns(),
            )
            .map_err(|e| format!("{e}\nchunk:\n{}", chunk.to_pretty())),
            Message::Watermark(watermark) => {
                let expected = info.schema.fields()[watermark.col_idx].data_type();
                let found = &watermark.data_type;
                if &expected != found {
                    Err(format!(
                        "watermark type mismatched: expected {expected}, found {found}"
                    ))
                } else {
                    Ok(())
                }
            }
            Message::Barrier(_) => Ok(()),
        }.unwrap_or_else

